package main

import (
	"fmt"
	"log"
	"math/rand"
	"net/http"
	"strconv"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requestsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "app_requests_total",
			Help: "Total number of application requests by user, method, and path.",
		},
		[]string{"user_id", "method", "path"},
	)

	activeRequests = prometheus.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "app_active_requests",
			Help: "Number of currently active requests per user.",
		},
		[]string{"user_id"},
	)

	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "app_request_duration_seconds",
			Help:    "Histogram of application request durations by user, method, path, and status code.",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"user_id", "method", "path", "status_code"},
	)
)

func init() {
	prometheus.MustRegister(requestsTotal)
	prometheus.MustRegister(activeRequests)
	prometheus.MustRegister(requestDuration)
}

func simulateRequest(w http.ResponseWriter, r *http.Request) {
	userID := fmt.Sprintf("user_%d", rand.Intn(1000))
	method := r.Method
	path := r.URL.Path

	activeRequests.WithLabelValues(userID).Inc()
	defer activeRequests.WithLabelValues(userID).Dec()

	start := time.Now()

	time.Sleep(time.Duration(rand.Intn(500)+50) * time.Millisecond)

	statusCode := http.StatusOK
	if rand.Intn(100) < 10 {
		statusCode = http.StatusInternalServerError
	} else if rand.Intn(100) < 20 {
		statusCode = http.StatusNotFound
	}

	requestsTotal.WithLabelValues(userID, method, path).Inc()

	duration := time.Since(start).Seconds()
	requestDuration.WithLabelValues(userID, method, path, strconv.Itoa(statusCode)).Observe(duration)

	w.WriteHeader(statusCode)
	fmt.Fprintf(w, "Request processed for user %s on path %s with status %d", userID, path, statusCode)
}

func main() {
	http.Handle("/metrics", promhttp.Handler())

	http.HandleFunc("/app", simulateRequest)
	http.HandleFunc("/app/data", simulateRequest)

	port := ":8080"
	log.Printf("Server starting on port %s", port)
	log.Printf("Metrics available at http://localhost%s/metrics", port)
	log.Printf("Simulate requests by accessing http://localhost%s/app or http://localhost%s/app/data", port, port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Could not start server: %s", err)
	}
}